'use client'

import { useEffect, useRef, useMemo, type CSSProperties, type ReactNode } from 'react'
import { renderShadow } from './render'
import type { ShadowConfig } from './types'
import { DEFAULT_CONFIG } from './types'

export interface FunkyShadowProps extends Partial<ShadowConfig> {
  /** Width of the element. Required. */
  width: number
  /** Height of the element. Required. */
  height: number
  /** Border radius of the element */
  radius?: number
  /** Additional class name on the wrapper */
  className?: string
  /** Additional styles on the wrapper */
  style?: CSSProperties
  children?: ReactNode
}

export function FunkyShadow({
  width,
  height,
  radius = 0,
  className,
  style,
  children,
  offsetX,
  offsetY,
  blur,
  opacity: opacityProp,
  preset,
  colors,
  shape,
  angle,
  spread,
  pixelScale,
  dither,
  quantLevels,
  oklab,
  contrast,
  brightness,
}: FunkyShadowProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  // Stable serialization key for colors array
  const colorsKey = colors ? JSON.stringify(colors) : ''

  const config = useMemo<Partial<ShadowConfig>>(() => {
    const c: Partial<ShadowConfig> = {}
    if (offsetX !== undefined) c.offsetX = offsetX
    if (offsetY !== undefined) c.offsetY = offsetY
    if (blur !== undefined) c.blur = blur
    if (opacityProp !== undefined) c.opacity = opacityProp
    if (preset !== undefined) c.preset = preset
    if (colors !== undefined) c.colors = colors
    if (shape !== undefined) c.shape = shape
    if (angle !== undefined) c.angle = angle
    if (spread !== undefined) c.spread = spread
    if (pixelScale !== undefined) c.pixelScale = pixelScale
    if (dither !== undefined) c.dither = dither
    if (quantLevels !== undefined) c.quantLevels = quantLevels
    if (oklab !== undefined) c.oklab = oklab
    if (contrast !== undefined) c.contrast = contrast
    if (brightness !== undefined) c.brightness = brightness
    return c
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [offsetX, offsetY, blur, opacityProp, preset, colorsKey, shape, angle, spread, pixelScale, dither, quantLevels, oklab, contrast, brightness])

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    renderShadow(canvas, width, height, radius, config)
  }, [width, height, radius, config])

  const resolvedOpacity = opacityProp ?? DEFAULT_CONFIG.opacity
  const cfg = { ...DEFAULT_CONFIG, ...config }
  const pad = cfg.blur * 2 + Math.max(Math.abs(cfg.offsetX), Math.abs(cfg.offsetY)) + 20
  const canvasW = width + pad * 2
  const canvasH = height + pad * 2

  return (
    <div
      className={className}
      style={{
        position: 'relative',
        width,
        height,
        ...style,
      }}
    >
      <canvas
        ref={canvasRef}
        style={{
          position: 'absolute',
          width: canvasW,
          height: canvasH,
          left: `calc(50% - ${canvasW / 2}px)`,
          top: `calc(50% - ${canvasH / 2}px)`,
          pointerEvents: 'none',
          imageRendering: 'pixelated',
          opacity: resolvedOpacity,
        }}
      />
      <div style={{ position: 'relative', zIndex: 1, width: '100%', height: '100%' }}>
        {children}
      </div>
    </div>
  )
}
