import type { ColorStops } from './presets'

export type GradientShape = 'line' | 'radial'
export type DitherMode = '8x8' | '4x4' | '2x2' | 'off'

export interface ShadowConfig {
  /** Shadow X offset in pixels */
  offsetX: number
  /** Shadow Y offset in pixels */
  offsetY: number
  /** Shadow blur radius in pixels */
  blur: number
  /** Shadow opacity 0-1 */
  opacity: number
  /** Gradient preset name or index */
  preset: string | number
  /** Custom color stops (overrides preset) */
  colors?: ColorStops
  /** Gradient shape */
  shape: GradientShape
  /** Gradient angle in degrees */
  angle: number
  /** Gradient spread 0-200 */
  spread: number
  /** Pixel scale (dot size) */
  pixelScale: number
  /** Dither matrix size */
  dither: DitherMode
  /** Color quantization levels 2-7 */
  quantLevels: number
  /** Use Oklab color space for interpolation */
  oklab: boolean
  /** Contrast adjustment 50-200 */
  contrast: number
  /** Brightness adjustment -50 to 50 */
  brightness: number
}

export const DEFAULT_CONFIG: ShadowConfig = {
  offsetX: -15,
  offsetY: 20,
  blur: 30,
  opacity: 0.7,
  preset: 'galaxy',
  shape: 'radial',
  angle: 45,
  spread: 120,
  pixelScale: 3,
  dither: '4x4',
  quantLevels: 4,
  oklab: true,
  contrast: 130,
  brightness: 0,
}
